1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: AXI-Lite Wrapper on AXI Stream Monitor Module
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_arith.all;
18	use ieee.std_logic_unsigned.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	use surf.AxiLitePkg.all;
24	
25	entity AxiStreamMonAxiL is
26	   generic (
27	      TPD_G            : time     := 1 ns;
28	      RST_POLARITY_G   : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
29	      RST_ASYNC_G      : boolean  := false;
30	      COMMON_CLK_G     : boolean  := false;      -- true if axisClk = axilClk
31	      AXIS_CLK_FREQ_G  : real     := 156.25E+6;  -- units of Hz
32	      AXIS_NUM_SLOTS_G : positive := 1;
33	      AXIS_CONFIG_G    : AxiStreamConfigType);
34	   port (
35	      -- AXIS Stream Interface
36	      axisClk          : in  sl;
37	      axisRst          : in  sl;
38	      axisMasters      : in  AxiStreamMasterArray(AXIS_NUM_SLOTS_G-1 downto 0);
39	      axisSlaves       : in  AxiStreamSlaveArray(AXIS_NUM_SLOTS_G-1 downto 0);
40	      -- AXI lite slave port for register access
41	      axilClk          : in  sl;
42	      axilRst          : in  sl;
43	      sAxilWriteMaster : in  AxiLiteWriteMasterType;
44	      sAxilWriteSlave  : out AxiLiteWriteSlaveType;
45	      sAxilReadMaster  : in  AxiLiteReadMasterType;
46	      sAxilReadSlave   : out AxiLiteReadSlaveType);
47	end AxiStreamMonAxiL;
48	
49	architecture rtl of AxiStreamMonAxiL is
50	
51	   constant ADDR_WIDTH_C : positive := bitSize(AXIS_NUM_SLOTS_G*16-1);
52	
53	   type RegType is record
54	      we   : sl;
55	      data : slv(31 downto 0);
56	      cnt  : slv(ADDR_WIDTH_C-1 downto 0);
57	      addr : slv(ADDR_WIDTH_C-1 downto 0);
58	      ch   : natural range 0 to AXIS_NUM_SLOTS_G-1;
59	   end record;
60	
61	   constant REG_INIT_C : RegType := (
62	      we   => '0',
63	      data => (others => '0'),
64	      cnt  => (others => '1'),  -- pre-set to all ones so 1st write after reset is address=0x0
65	      addr => (others => '1'),  -- pre-set to all ones so 1st write after reset is address=0x0
66	      ch   => 0);
67	
68	   signal r   : RegType := REG_INIT_C;
69	   signal rin : RegType;
70	
71	   signal rstCnt     : sl;
72	   signal localReset : sl;
73	   signal axisReset  : sl;
74	
75	   signal frameCnt : Slv64Array(AXIS_NUM_SLOTS_G-1 downto 0);
76	
77	   signal frameSize    : Slv32Array(AXIS_NUM_SLOTS_G-1 downto 0);
78	   signal frameSizeMax : Slv32Array(AXIS_NUM_SLOTS_G-1 downto 0);
79	   signal frameSizeMin : Slv32Array(AXIS_NUM_SLOTS_G-1 downto 0);
80	
81	   signal frameRate    : Slv32Array(AXIS_NUM_SLOTS_G-1 downto 0);
82	   signal frameRateMax : Slv32Array(AXIS_NUM_SLOTS_G-1 downto 0);
83	   signal frameRateMin : Slv32Array(AXIS_NUM_SLOTS_G-1 downto 0);
84	
85	   signal bandwidth    : Slv64Array(AXIS_NUM_SLOTS_G-1 downto 0);
86	   signal bandwidthMax : Slv64Array(AXIS_NUM_SLOTS_G-1 downto 0);
87	   signal bandwidthMin : Slv64Array(AXIS_NUM_SLOTS_G-1 downto 0);
88	
89	   -- attribute dont_touch                 : string;
90	   -- attribute dont_touch of r            : signal is "true";
91	   -- attribute dont_touch of rstCnt       : signal is "true";
92	   -- attribute dont_touch of localReset   : signal is "true";
93	   -- attribute dont_touch of axisReset    : signal is "true";
94	   -- attribute dont_touch of frameCnt     : signal is "true";
95	   -- attribute dont_touch of frameSize    : signal is "true";
96	   -- attribute dont_touch of frameSizeMax : signal is "true";
97	   -- attribute dont_touch of frameSizeMin : signal is "true";
98	   -- attribute dont_touch of frameRate    : signal is "true";
99	   -- attribute dont_touch of frameRateMax : signal is "true";
100	   -- attribute dont_touch of frameRateMin : signal is "true";
101	   -- attribute dont_touch of bandwidth    : signal is "true";
102	   -- attribute dont_touch of bandwidthMax : signal is "true";
103	   -- attribute dont_touch of bandwidthMin : signal is "true";
104	
105	begin
106	
107	   -- Only doing a write address decode of 0x0
108	   rstCnt          <= sAxilWriteMaster.awvalid when(sAxilWriteMaster.awaddr(ADDR_WIDTH_C+1 downto 0) = 0) else '0';
109	   sAxilWriteSlave <= AXI_LITE_WRITE_SLAVE_EMPTY_OK_C;
110	
111	   localReset <= axisRst or rstCnt when(RST_POLARITY_G = '1') else axisRst and not(rstCnt);
112	
113	   U_RstSync : entity surf.RstSync
114	      generic map (
115	         TPD_G          => TPD_G,
116	         IN_POLARITY_G  => RST_POLARITY_G,
117	         OUT_POLARITY_G => RST_POLARITY_G)
118	      port map (
119	         clk      => axisClk,
120	         asyncRst => localReset,
121	         syncRst  => axisReset);
122	
123	   GEN_VEC : for i in 0 to (AXIS_NUM_SLOTS_G-1) generate
124	
125	      U_AxiStreamMon : entity surf.AxiStreamMon
126	         generic map(
127	            TPD_G           => TPD_G,
128	            RST_POLARITY_G  => RST_POLARITY_G,
129	            RST_ASYNC_G     => RST_ASYNC_G,
130	            COMMON_CLK_G    => true,             -- true if axisClk = statusClk
131	            AXIS_CLK_FREQ_G => AXIS_CLK_FREQ_G,  -- units of Hz
132	            AXIS_CONFIG_G   => AXIS_CONFIG_G)
133	         port map(
134	            -- AXIS Stream Interface
135	            axisClk      => axisClk,
136	            axisRst      => axisReset,
137	            axisMaster   => axisMasters(i),
138	            axisSlave    => axisSlaves(i),
139	            -- Status Clock and reset
140	            statusClk    => axisClk,
141	            statusRst    => axisReset,
142	            -- Status: Total number of frame received since statusRst
143	            frameCnt     => frameCnt(i),
144	            -- Status: Frame Size (units of Byte)
145	            frameSize    => frameSize(i),
146	            frameSizeMax => frameSizeMax(i),
147	            frameSizeMin => frameSizeMin(i),
148	            -- Status: Frame rate (units of Hz)
149	            frameRate    => frameRate(i),
150	            frameRateMax => frameRateMax(i),
151	            frameRateMin => frameRateMin(i),
152	            -- Status: Bandwidth (units of Byte/s)
153	            bandwidth    => bandwidth(i),
154	            bandwidthMax => bandwidthMax(i),
155	            bandwidthMin => bandwidthMin(i));
156	
157	   end generate;
158	
159	   U_AxiDualPortRam : entity surf.AxiDualPortRam
160	      generic map (
161	         TPD_G          => TPD_G,
162	         RST_POLARITY_G => RST_POLARITY_G,
163	         RST_ASYNC_G    => RST_ASYNC_G,
164	         SYNTH_MODE_G   => "inferred",
165	         MEMORY_TYPE_G  => ite(ADDR_WIDTH_C > 5, "block", "distributed"),
166	         READ_LATENCY_G => ite(ADDR_WIDTH_C > 5, 2, 1),
167	         AXI_WR_EN_G    => false,
168	         SYS_WR_EN_G    => true,
169	         COMMON_CLK_G   => false,
170	         ADDR_WIDTH_G   => ADDR_WIDTH_C,
171	         DATA_WIDTH_G   => 32)
172	      port map (
173	         -- Axi Port
174	         axiClk         => axilClk,
175	         axiRst         => axilRst,
176	         axiReadMaster  => sAxilReadMaster,
177	         axiReadSlave   => sAxilReadSlave,
178	         axiWriteMaster => AXI_LITE_WRITE_MASTER_INIT_C,
179	         axiWriteSlave  => open,
180	         -- Standard Port
181	         clk            => axisClk,
182	         rst            => axisRst,
183	         we             => r.we,
184	         addr           => r.addr,
185	         din            => r.data);
186	
187	   comb : process (axisRst, bandwidth, bandwidthMax, bandwidthMin, frameCnt,
188	                   frameRate, frameRateMax, frameRateMin, frameSize,
189	                   frameSizeMax, frameSizeMin, r) is
190	      variable v   : RegType;
191	      variable wrd : slv(3 downto 0);
192	   begin
193	      -- Latch the current value
194	      v := r;
195	
196	      -- Increment the counter
197	      v.cnt := r.cnt + 1;
198	
199	      -- Write the status counter to RAM
200	      v.we   := '1';
201	      v.addr := v.cnt;
202	
203	      -- Case on the word index
204	      wrd := v.addr(3 downto 0);
205	      case (wrd) is
206	         ----------------------------------------------------------------------
207	         when x"0" =>  -- i*0x40 + 0x00: DMA AXI Stream Configuration (debugging)
208	
209	            v.data(31 downto 24) := toSlv(AXIS_CONFIG_G.TDATA_BYTES_C, 8);
210	            v.data(23 downto 20) := toSlv(AXIS_CONFIG_G.TDEST_BITS_C, 4);
211	            v.data(19 downto 16) := toSlv(AXIS_CONFIG_G.TUSER_BITS_C, 4);
212	            v.data(15 downto 12) := toSlv(AXIS_CONFIG_G.TID_BITS_C, 4);
213	
214	            case AXIS_CONFIG_G.TKEEP_MODE_C is
215	               when TKEEP_NORMAL_C => v.data(11 downto 8) := x"0";
216	               when TKEEP_COMP_C   => v.data(11 downto 8) := x"1";
217	               when TKEEP_FIXED_C  => v.data(11 downto 8) := x"2";
218	               when TKEEP_COUNT_C  => v.data(11 downto 8) := x"3";
219	               when others         => v.data(11 downto 8) := x"F";
220	            end case;
221	
222	            case AXIS_CONFIG_G.TUSER_MODE_C is
223	               when TUSER_NORMAL_C     => v.data(7 downto 4) := x"0";
224	               when TUSER_FIRST_LAST_C => v.data(7 downto 4) := x"1";
225	               when TUSER_LAST_C       => v.data(7 downto 4) := x"2";
226	               when TUSER_NONE_C       => v.data(7 downto 4) := x"3";
227	               when others             => v.data(7 downto 4) := x"F";
228	            end case;
229	
230	            v.data(3) := '0';
231	            v.data(2) := '0';
232	            v.data(1) := ite(AXIS_CONFIG_G.TSTRB_EN_C, '1', '0');
233	            v.data(0) := ite(COMMON_CLK_G, '1', '0');
234	
235	         ----------------------------------------------------------------------
236	         when x"1" => v.data := frameCnt(r.ch)(31 downto 0);   -- i*0x40 + 0x04
237	         when x"2" => v.data := frameCnt(r.ch)(63 downto 32);  -- i*0x40 + 0x08
238	         ----------------------------------------------------------------------
239	         when x"3" => v.data := frameRate(r.ch);               -- i*0x40 + 0x0C
240	         when x"4" => v.data := frameRateMax(r.ch);            -- i*0x40 + 0x10
241	         when x"5" => v.data := frameRateMin(r.ch);            -- i*0x40 + 0x14
242	         ----------------------------------------------------------------------
243	         when x"6" => v.data := bandwidth(r.ch)(31 downto 0);  -- i*0x40 + 0x18
244	         when x"7" => v.data := bandwidth(r.ch)(63 downto 32);  -- i*0x40 + 0x1C
245	         when x"8" => v.data := bandwidthMax(r.ch)(31 downto 0);  -- i*0x40 + 0x20
246	         when x"9" => v.data := bandwidthMax(r.ch)(63 downto 32);  -- i*0x40 + 0x24
247	         when x"A" => v.data := bandwidthMin(r.ch)(31 downto 0);  -- i*0x40 + 0x28
248	         when x"B" => v.data := bandwidthMin(r.ch)(63 downto 32);  -- i*0x40 + 0x2C
249	         ----------------------------------------------------------------------
250	         when x"C" => v.data := frameSize(r.ch);               -- i*0x40 + 0x30
251	         when x"D" => v.data := frameSizeMax(r.ch);            -- i*0x40 + 0x34
252	         when x"E" => v.data := frameSizeMin(r.ch);            -- i*0x40 + 0x38
253	         ----------------------------------------------------------------------
254	         when x"F" =>                   -- i*0x40 + 0x3C: Debugging
255	            v.data(7 downto 0)   := toSlv(AXIS_NUM_SLOTS_G, 8);
256	            v.data(15 downto 8)  := toSlv(ADDR_WIDTH_C, 8);
257	            v.data(23 downto 16) := toSlv(r.ch, 8);
258	            v.data(31 downto 16) := (others => '0');
259	         -----------------------------------------------------------------------
260	         when others =>
261	            v.we := '0';
262	      -----------------------------------------------------------------------
263	      end case;
264	
265	      -- Check for last word
266	      if (wrd = x"F") then
267	
268	         -- Check for last word
269	         if (r.ch = AXIS_NUM_SLOTS_G-1) then
270	            -- Reset the counters
271	            v.ch  := 0;
272	            v.cnt := (others => '1');  -- pre-set to all ones so 1st write after reset is address=0x0
273	         else
274	            -- Increment the counters
275	            v.ch := r.ch + 1;
276	         end if;
277	
278	      end if;
279	
280	      -- Synchronous Reset
281	      if (RST_ASYNC_G = false and axisRst = RST_POLARITY_G) then
282	         v := REG_INIT_C;
283	      end if;
284	
285	      -- Register the variable for next clock cycle
286	      rin <= v;
287	
288	   end process comb;
289	
290	   seq : process (axisClk, axisRst) is
291	   begin
292	      if (RST_ASYNC_G) and (axisRst = RST_POLARITY_G) then
293	         r <= REG_INIT_C after TPD_G;
294	      elsif rising_edge(axisClk) then
295	         r <= rin after TPD_G;
296	      end if;
297	   end process seq;
298	
299	end rtl;
