1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Generates pseudo-random back pressure
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	
24	entity AxiStreamPrbsFlowCtrl is
25	   generic (
26	      TPD_G          : time                 := 1 ns;
27	      RST_POLARITY_G : sl                   := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
28	      RST_ASYNC_G    : boolean              := false;
29	      PIPE_STAGES_G  : natural range 0 to 1 := 0;
30	      SEED_G         : slv(31 downto 0)     := x"AAAA_5555";
31	      PRBS_TAPS_G    : NaturalArray         := (0 => 31, 1 => 6, 2 => 2, 3 => 1));
32	   port (
33	      clk         : in  sl;
34	      rst         : in  sl;
35	      threshold   : in  slv(31 downto 0) := x"8000_0000";
36	      -- Slave Port
37	      sAxisMaster : in  AxiStreamMasterType;
38	      sAxisSlave  : out AxiStreamSlaveType;
39	      -- Master Port
40	      mAxisMaster : out AxiStreamMasterType;
41	      mAxisSlave  : in  AxiStreamSlaveType);
42	end AxiStreamPrbsFlowCtrl;
43	
44	architecture rtl of AxiStreamPrbsFlowCtrl is
45	
46	   type RegType is record
47	      randomData : slv(31 downto 0);
48	      rxSlave    : AxiStreamSlaveType;
49	      txMaster   : AxiStreamMasterType;
50	   end record RegType;
51	   constant REG_INIT_C : RegType := (
52	      randomData => SEED_G,
53	      rxSlave    => AXI_STREAM_SLAVE_INIT_C,
54	      txMaster   => AXI_STREAM_MASTER_INIT_C);
55	
56	   signal r   : RegType := REG_INIT_C;
57	   signal rin : RegType;
58	
59	   signal rxMaster : AxiStreamMasterType;
60	   signal rxSlave  : AxiStreamSlaveType;
61	   signal txMaster : AxiStreamMasterType;
62	   signal txSlave  : AxiStreamSlaveType;
63	   signal pause    : sl;
64	
65	begin
66	
67	   rxMaster   <= sAxisMaster;
68	   sAxisSlave <= rxSlave;
69	
70	   U_DspComparator : entity surf.DspComparator
71	      generic map (
72	         TPD_G          => TPD_G,
73	         RST_POLARITY_G => RST_POLARITY_G,
74	         RST_ASYNC_G    => RST_ASYNC_G,
75	         WIDTH_G        => 32)
76	      port map (
77	         clk => clk,
78	         ain => r.randomData,
79	         bin => threshold,
80	         ls  => pause);                 --  (a <  b)
81	
82	   comb : process (pause, r, rst, rxMaster, txSlave) is
83	      variable v : RegType;
84	      variable i : natural;
85	   begin
86	      -- Latch the current value
87	      v := r;
88	
89	      -- Reset the flags
90	      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
91	      if (txSlave.tReady = '1') then
92	         v.txMaster.tValid := '0';
93	      end if;
94	
95	      -- Generate new random data
96	      v.randomData := lfsrShift(r.randomData, PRBS_TAPS_G, '0');
97	
98	      -- Check if ready to move data
99	      if (v.txMaster.tValid = '0') and (rxMaster.tValid = '1') and (pause = '0') then
100	         -- Accept the data
101	         v.rxSlave.tReady := '1';
102	         -- Move the data
103	         v.txMaster       := rxMaster;
104	      end if;
105	
106	      -- Combinatorial outputs before the reset
107	      rxSlave <= v.rxSlave;
108	
109	      -- Reset
110	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
111	         v := REG_INIT_C;
112	      end if;
113	
114	      -- Register the variable for next clock cycle
115	      rin <= v;
116	
117	      -- Outputs
118	      txMaster <= r.txMaster;
119	
120	   end process comb;
121	
122	   seq : process (clk, rst) is
123	   begin
